import React, { useEffect, useState, useCallback, useMemo, useId } from "react";
import { useForm, Controller, useFormContext, FormProvider } from "react-hook-form";
import "react-quill-new/dist/quill.snow.css";
import {
    Loader2, AlertCircle, RefreshCw,
    Mail, Calendar as CalendarIcon, Hash, Type, FileText, ChevronDown,
} from "lucide-react";
import { cn } from "@/shadcn/lib/utils";
import { formMetadataService as accountService } from "@/api/auth/formMetadataService";
import { Button } from "@/shadcn/components/ui/button";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/shadcn/components/ui/select";
import { Checkbox } from "@/shadcn/components/ui/checkbox";
import { RadioGroup, RadioGroupItem } from "@/shadcn/components/ui/radio-group";
import { Textarea } from "@/shadcn/components/ui/textarea";
import { Label } from "@/shadcn/components/ui/label";
import CustomQuill from "../ui/CustomQuill";
import { HarmonyInput as Input } from "../ui/harmony-input";

/* ============================
   TYPE DEFINITIONS
   ============================ */

export interface FieldOption {
    value: string | number;
    label: string;
}

export interface ValidationRule {
    type: string;
    value?: any;
    message: string;
}

export interface FieldMetadata {
    name: string;
    label: string;
    inputType: string | "text" | "select" | "radio" | "collection" | "object" | "quill" | "date" | "datetime-local" | "textarea" | "number";
    required?: boolean;
    options?: FieldOption[];
    validations?: ValidationRule[];
    itemSchema?: FormSchema;
    nestedSchema?: FormSchema;
}

export interface FormSchema {
    formKey: string;
    title: string;
    fields: FieldMetadata[];
}

interface HarmonyFormProps {
    dtoName?: string;
    schema?: FormSchema | null;
    onSubmit: (data: any) => void;
    onCancel?: () => void;
    defaultValues?: Record<string, any> | null;
    initialValues?: Record<string, any> | null;
    submitLabel?: string;
    hideSubmitButton?: boolean;
    isPending?: boolean;
}

/* ============================
   SUB-COMPONENTS
   ============================ */

const getFieldStyles = (error: any) =>
    cn(
        "px-3 rounded-xl border bg-card text-sm font-medium text-foreground transition-all",
        "focus:outline-none focus:ring-2 focus:ring-ring/20",
        error ? "border-destructive focus:ring-destructive/20" : "border-border hover:border-ring/50"
    );

const MultiSelectField = ({ field, value, onChange, error, id }: any) => {
    const [isOpen, setIsOpen] = useState(false);
    const selectedValues = Array.isArray(value) ? value.map((val) => String(val)) : [];
    const selectedLabels = field.options
        ?.filter((opt: any) => selectedValues.includes(String(opt.value)))
        .map((opt: any) => opt.label)
        .join(", ");

    return (
        <div className="relative">
            <button
                id={id}
                type="button"
                onClick={() => setIsOpen((prev) => !prev)}
                className={`${getFieldStyles(error)} flex items-center justify-between gap-3 text-left w-full h-[46px]`}
                aria-expanded={isOpen}
                aria-haspopup="listbox"
            >
                <span className="truncate">
                    {selectedLabels || `Select ${field.label}...`}
                </span>
                <ChevronDown size={16} className={`transition-transform ${isOpen ? "rotate-180" : ""}`} />
            </button>
            {isOpen && (
                <div className="absolute z-10 w-full mt-2 rounded-xl border border-slate-200 bg-white shadow-xl p-2 max-h-60 overflow-y-auto space-y-1">
                    {field.options?.map((opt: any) => {
                        const optionValue = String(opt.value);
                        const isChecked = selectedValues.includes(optionValue);
                        return (
                            <label
                                key={optionValue}
                                className={`flex items-center gap-3 rounded-lg px-3 py-2 text-[13px] transition cursor-pointer ${
                                    isChecked ? "bg-indigo-50/70" : "hover:bg-slate-50"
                                }`}
                            >
                                <input
                                    type="checkbox"
                                    className="h-4 w-4 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500/20 cursor-pointer"
                                    checked={isChecked}
                                    onChange={(e) => {
                                        if (e.target.checked) {
                                            onChange([...selectedValues, optionValue]);
                                        } else {
                                            onChange(selectedValues.filter((v: any) => v !== optionValue));
                                        }
                                    }}
                                />
                                <span className="select-none font-medium">{opt.label}</span>
                            </label>
                        );
                    })}
                </div>
            )}
        </div>
    );
};

const FormInputSnippet = ({
    field,
    value,
    onChange,
    error,
    id,
}: {
    field: FieldMetadata;
    value: any;
    onChange: (v: any) => void;
    error?: any;
    id: string;
}) => {
    if (field.inputType === "collection" || field.inputType === "object") return null;

    // QUILL / RICH TEXT
    if (field.inputType === "quill" || field.name.toLowerCase().includes("description")) {
        return (
            <div
                className={cn(
                    "bg-card rounded-xl border overflow-hidden transition-all",
                    "focus-within:border-ring focus-within:ring-2 focus-within:ring-ring/20",
                    error ? "border-destructive" : "border-border"
                )}
                aria-invalid={error ? "true" : "false"}
            >
                <CustomQuill
                    value={value ?? ""}
                    onChange={onChange}
                    placeholder={`Enter ${field.label.toLowerCase()}...`}
                />
            </div>
        );
    }

    // CHECKBOX / BOOLEAN
    if (field.inputType === "checkbox" || field.inputType === "boolean") {
        return (
            <div className="flex items-center gap-3 h-11">
                <Checkbox
                    id={id}
                    checked={Boolean(value)}
                    onCheckedChange={(checked) => onChange(Boolean(checked))}
                    aria-invalid={error ? true : undefined}
                />
                <Label htmlFor={id} className="text-sm font-medium text-foreground cursor-pointer">
                    {field.label}
                </Label>
            </div>
        );
    }

    // SELECT / DROPDOWN
    if (field.inputType === "multiselect") {
        return <MultiSelectField field={field} value={value} onChange={onChange} error={error} id={id} />;
    }

    if (field.inputType === "select" || (Array.isArray(field.options) && field.inputType !== "radio")) {
        return (
            <Select
                value={String(value) || ""}
                onValueChange={(v) => onChange(v)}
            >
                <SelectTrigger
                    className="w-full"
                    aria-invalid={error ? true : undefined}
                >
                    <SelectValue placeholder={`Select ${field.label}...`} />
                </SelectTrigger>
                <SelectContent>
                    {field.options?.map((opt: any) => (
                        <SelectItem key={opt.value} value={String(opt.value)}>
                            {opt.label}
                        </SelectItem>
                    ))}
                </SelectContent>
            </Select>
        );
    }

    // RADIO BUTTONS
    if (field.inputType === "radio") {
        return (
            <RadioGroup
                value={String(value)}
                onValueChange={(v) => onChange(v)}
                className="flex flex-wrap gap-3"
                aria-labelledby={`${id}-label`}
            >
                {field.options?.map((opt: any) => (
                    <div
                        key={opt.value}
                        className="flex flex-1 min-w-[140px] items-center gap-3 p-3 rounded-lg border border-border bg-card cursor-pointer hover:bg-accent transition-all hover:shadow-sm"
                    >
                        <RadioGroupItem
                            value={String(opt.value)}
                            id={`${id}-${opt.value}`}
                        />
                        <Label
                            htmlFor={`${id}-${opt.value}`}
                            className="text-xs font-bold text-muted-foreground hover:text-foreground transition-colors uppercase tracking-tight cursor-pointer"
                        >
                            {opt.label}
                        </Label>
                    </div>
                ))}
            </RadioGroup>
        );
    }

    // TEXTAREA
    if (field.inputType === "textarea") {
        return (
            <Textarea
                id={id}
                value={value ?? ""}
                onChange={(e) => onChange(e.target.value)}
                rows={4}
                placeholder={`Enter ${field.label.toLowerCase()}...`}
                aria-invalid={error ? true : undefined}
            />
        );
    }

    // DEFAULT (text, date, email, number, etc.)
    const getInputIcon = () => {
        if (field.inputType === "number") return <Hash size={14} />;
        if (field.inputType === "date" || field.inputType === "datetime-local") return <CalendarIcon size={14} />;
        if (field.inputType === "email" || field.name.toLowerCase().includes("email")) return <Mail size={14} />;
        if (field.inputType === "textarea") return <FileText size={14} />;
        return <Type size={14} />;
    };

    return (
        <Input
            id={id}
            label={field.label}
            type={field.inputType || "text"}
            value={value ?? ""}
            onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                const val = e.target.value;
                onChange(field.inputType === "number" ? (val === "" ? "" : Number(val)) : val);
            }}
            placeholder={`Enter ${field.label.toLowerCase()}...`}
            error={error?.message}
            leftIcon={getInputIcon()}
        />
    );
};

const FormFieldsRecursive = ({
    schema,
    prefix = "",
    instanceId,
}: {
    schema: FormSchema;
    prefix?: string;
    instanceId: string;
}) => {
    const { control, formState: { errors } } = useFormContext();

    const getValidationRules = (field: FieldMetadata) => {
        const rules: any = {};
        if (!field.validations) return rules;
        field.validations.forEach((v) => {
            switch (v.type) {
                case "required": rules.required = v.message || "Required"; break;
                case "regex": rules.pattern = { value: new RegExp(String(v.value)), message: v.message || "Invalid format" }; break;
                case "minLength": rules.minLength = { value: Number(v.value), message: v.message }; break;
                case "maxLength": rules.maxLength = { value: Number(v.value), message: v.message }; break;
            }
        });
        if (field.required && !rules.required) rules.required = "This field is required";
        return rules;
    };

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-x-10 gap-y-8">
            {schema.fields.map((field) => {
                const fieldName = prefix ? `${prefix}.${field.name}` : field.name;
                const fieldId = `${instanceId}-${fieldName}`.replace(/\./g, '-');
                const error = fieldName.split('.').reduce((obj, key) => obj?.[key], errors as any);

                const isFullWidth =
                    field.inputType === "collection" ||
                    field.inputType === "object" ||
                    field.inputType === "quill" ||
                    field.inputType === "textarea" ||
                    field.name.toLowerCase().includes("description");

                return (
                    <div
                        key={fieldName}
                        className={`flex flex-col gap-3 animate-in fade-in slide-in-from-bottom-3 duration-700 ${isFullWidth ? "md:col-span-2" : ""}`}
                    >
                        <Controller
                            name={fieldName}
                            control={control}
                            rules={getValidationRules(field)}
                            render={({ field: { value, onChange } }) => (
                                <>
                                    <FormInputSnippet
                                        field={field}
                                        value={value}
                                        onChange={onChange}
                                        error={error}
                                        id={fieldId}
                                    />

                                    {/* NESTED OBJECT */}
                                    {field.inputType === "object" && field.nestedSchema && (
                                        <div className="bg-muted/30 p-6 rounded-xl border border-border space-y-6">
                                            <div className="flex flex-col gap-0.5">
                                                <p className="text-[10px] font-bold text-primary uppercase tracking-widest">
                                                    {field.label}
                                                </p>
                                                <p className="text-[9px] text-muted-foreground font-bold uppercase tracking-widest">
                                                    Linked Group Configuration
                                                </p>
                                            </div>
                                            <FormFieldsRecursive
                                                schema={field.nestedSchema}
                                                prefix={fieldName}
                                                instanceId={instanceId}
                                            />
                                        </div>
                                    )}

                                    {/* NESTED COLLECTION (ARRAYS) */}
                                    {field.inputType === "collection" && field.itemSchema && (
                                        <div className="space-y-6 mt-4">
                                            <div className="flex items-center gap-4">
                                                <div className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center border border-primary/20">
                                                    <RefreshCw size={14} className="text-primary" />
                                                </div>
                                                <div className="flex flex-col">
                                                    <span className="text-[11px] font-black text-foreground uppercase tracking-widest">
                                                        {field.label} Registry
                                                    </span>
                                                    <span className="text-[9px] font-bold text-muted-foreground uppercase tracking-tighter">
                                                        Multiple records supported
                                                    </span>
                                                </div>
                                                <div className="h-px bg-border flex-1" />
                                            </div>

                                            <div className="grid grid-cols-1 gap-8">
                                                {(Array.isArray(value) ? value : [{}]).map((_: any, idx: number) => (
                                                    <div
                                                        key={idx}
                                                        className="bg-card p-8 sm:p-10 rounded-2xl border border-border border-l-4 border-l-primary space-y-8 relative shadow-sm hover:shadow-md transition-all"
                                                    >
                                                        <div className="absolute -top-3 right-8">
                                                            <span className="px-3 py-1 bg-primary text-primary-foreground text-[9px] font-black uppercase tracking-widest rounded-full shadow-sm">
                                                                #{idx + 1}
                                                            </span>
                                                        </div>
                                                        <FormFieldsRecursive
                                                            schema={field.itemSchema!}
                                                            prefix={`${fieldName}.${idx}`}
                                                            instanceId={instanceId}
                                                        />
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    )}
                                </>
                            )}
                        />
                    </div>
                );
            })}
        </div>
    );
};

/* ============================
   MAIN COMPONENT
   ============================ */

const HarmonyForm: React.FC<HarmonyFormProps> = ({
    dtoName,
    schema: manualSchema,
    onSubmit,
    onCancel,
    defaultValues = null,
    initialValues = null,
    submitLabel,
    hideSubmitButton = false,
    isPending = false,
}) => {
    const instanceId = useId();
    const [schema, setSchema] = useState<FormSchema | null>(null);
    const [error, setError] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);
    const [retryTrigger, setRetryTrigger] = useState(0);

    const effectiveValues = useMemo(() => defaultValues || initialValues, [defaultValues, initialValues]);
    const methods = useForm({ mode: "onChange" });

    /**
     * Deep normalization logic. Handles recursive mapping and date formatting.
     * Preserves fields not found in the schema (like IDs) for updates.
     */
    const normalizeData = useCallback((values: any, schemaData: FormSchema): any => {
        if (!values || !schemaData?.fields) return values;
        const mapped: any = { ...values };

        schemaData.fields.forEach((field) => {
            const rawKey = Object.keys(values).find(k => k.toLowerCase() === field.name.toLowerCase());
            const value = rawKey ? values[rawKey] : undefined;

            if (value === undefined || value === null || value === "") {
                if (field.inputType === "collection") mapped[field.name] = [];
                else if (field.inputType === "object") mapped[field.name] = {};
                else mapped[field.name] = null;
                return;
            }

            if (field.inputType === "collection" && field.itemSchema && Array.isArray(value)) {
                mapped[field.name] = value.map(v => normalizeData(v, field.itemSchema!));
                return;
            }

            if (field.inputType === "object" && field.nestedSchema) {
                mapped[field.name] = normalizeData(value, field.nestedSchema);
                return;
            }

            if (typeof value === "string" && value.includes("T")) {
                if (field.inputType === "date") {
                    mapped[field.name] = value.split("T")[0];
                    return;
                }
                if (field.inputType === "datetime-local") {
                    mapped[field.name] = value.slice(0, 16);
                    return;
                }
            }

            mapped[field.name] = value;
        });

        return mapped;
    }, []);

    const fetchSchema = useCallback(async () => {
        if (!dtoName) return;
        try {
            setLoading(true);
            const data = await accountService.getFormMetadata(dtoName);
            setSchema(data);
            setError(null);
        } catch (err: any) {
            setError(err.message || "Failed to load form metadata");
        } finally {
            setLoading(false);
        }
    }, [dtoName]);

    useEffect(() => {
        if (manualSchema) {
            setSchema(manualSchema);
            setLoading(false);
            return;
        }
        if (dtoName) {
            fetchSchema();
        }
    }, [fetchSchema, retryTrigger, manualSchema, dtoName]);

    useEffect(() => {
        if (schema && effectiveValues) {
            methods.reset(normalizeData(effectiveValues, schema));
        }
    }, [schema, effectiveValues, normalizeData, methods]);

    if (loading) {
        return (
            <div className="p-10 space-y-10">
                <div className="grid grid-cols-2 gap-8">
                    <div className="h-14 bg-muted rounded-xl animate-pulse" />
                    <div className="h-14 bg-muted rounded-xl animate-pulse" />
                </div>
                <div className="h-3 bg-muted rounded-full w-1/4 animate-pulse" />
                <div className="h-40 bg-muted rounded-xl animate-pulse" />
            </div>
        );
    }

    if (error) {
        return (
            <div className="p-10 bg-destructive/5 border border-destructive/20 rounded-xl flex flex-col items-center gap-6 text-center">
                <div className="w-16 h-16 bg-card rounded-2xl flex items-center justify-center shadow-sm text-destructive ring-4 ring-destructive/10">
                    <AlertCircle className="w-8 h-8" />
                </div>
                <div>
                    <h4 className="text-destructive font-black text-lg uppercase tracking-widest">
                        Configuration Error
                    </h4>
                    <p className="text-destructive/70 text-sm font-medium mt-1 max-w-xs mx-auto">{error}</p>
                </div>
                <Button
                    type="button"
                    variant="destructive"
                    onClick={() => setRetryTrigger(t => t + 1)}
                >
                    <RefreshCw className="w-4 h-4" />
                    Retry
                </Button>
            </div>
        );
    }

    if (!schema) return null;

    return (
        <FormProvider {...methods}>
            <form onSubmit={methods.handleSubmit(onSubmit)} className="space-y-12">
                <FormFieldsRecursive schema={schema} instanceId={instanceId} />

                <div className="pt-8 flex items-center justify-end gap-3">
                    {onCancel && (
                        <Button type="button" variant="outline" onClick={onCancel}>
                            Cancel
                        </Button>
                    )}
                    {!hideSubmitButton && (
                        <Button
                            type="submit"
                            disabled={methods.formState.isSubmitting || isPending}
                        >
                            {(methods.formState.isSubmitting || isPending) ? (
                                <>
                                    <Loader2 className="w-4 h-4 animate-spin" />
                                    Saving...
                                </>
                            ) : (
                                submitLabel || "Submit Changes"
                            )}
                        </Button>
                    )}
                </div>
            </form>
        </FormProvider>
    );
};

export default HarmonyForm;
